sp_widget.client_script:
api.controller = function($scope, $location) {
    /* widget controller */
    var c = this;

	c.onCancel = function() {
		$scope.$parent.$parent.$dismiss();
	};

	c.onSubmit = function() {
		c.data.submit = true;
		$scope.server.update().then(function(){

			// DFCT0010541
			var srch = $location.search();
			if (c.data.parent != ''){
				srch.sys_id = c.data.parent;
				$location.search(srch);
			} else {
				window.location.href = '../discovertaskerportal';
			}
			$scope.$parent.$parent.$dismiss();
		});
	};
};

sp_widget.script:
